const activeIds = flow.get('activeSlaveIds', 'file') || [];
if (activeIds.length === 0) return null;

flow.set('bgScanQueue', activeIds.slice(1), 'file');

return [{ 
    payload: { value: 0, unitid: activeIds[0], fc: 3, address: 2, quantity: 1 }, 
    slaveId: activeIds[0], 
    scanType: 'slow' 
}];

let slaveId = (msg.modbusRequest && msg.modbusRequest.unitid) || (msg.payload && msg.payload.unitid) || (msg.payload && msg.payload.modbusRequest && msg.payload.modbusRequest.unitid) || msg.slaveId || null;
if (!slaveId) { node.warn('OFFLINE: slaveId not found'); return null; }

let tableData = flow.get('tableData', 'file') || {};
let existing = tableData['slave_' + slaveId];
let now = Date.now();

if (existing && existing.lastSeen && (now - existing.lastSeen) < 5000) {
    const SLAVE_IDS = flow.get('slaveIds', 'file') || [];
    msg.payload = SLAVE_IDS.map(id => tableData['slave_' + id] || { 
        ID: id, Location: '', RoomNo: '', DPValue: '—', LSP: -60, HSP: 60, Alarm: 'OFFLINE', Status: 'OFFLINE', lastSeen: 0 
    });
    return msg;
}

let settings = flow.get('deviceSettings', 'file') || {};
let device = settings['slave_' + slaveId] || { Location: '', RoomNo: '', LSP: -60, HSP: 60 };

tableData['slave_' + slaveId] = { 
    ID: slaveId, 
    Location: device.Location, 
    RoomNo: device.RoomNo, 
    DPValue: '—', 
    LSP: device.LSP, 
    HSP: device.HSP, 
    Alarm: 'OFFLINE', 
    Status: 'OFFLINE', 
    lastSeen: existing ? existing.lastSeen : 0 
};
flow.set('tableData', tableData, 'file');

let onlineIds = flow.get('onlineIds', 'file') || [];
let idx = onlineIds.indexOf(slaveId);
if (idx !== -1) { 
    onlineIds.splice(idx, 1); 
    flow.set('onlineIds', onlineIds, 'file'); 
}

const SLAVE_IDS = flow.get('slaveIds', 'file') || [];
msg.payload = SLAVE_IDS.map(id => tableData['slave_' + id] || { 
    ID: id, Location: '', RoomNo: '', DPValue: '—', LSP: -60, HSP: 60, Alarm: 'OFFLINE', Status: 'OFFLINE', lastSeen: 0 
});

return msg;

if (!msg._logEntry) return null;

const e = msg._logEntry;

if (typeof e.slaveId === 'undefined' || typeof e.dpValue === 'undefined') {
    node.warn("[dp_log] Missing slaveId or dpValue");
    return null;
}

const dt = new Date(e.ts);

if (isNaN(dt.getTime())) {
    node.warn(`[dp_log] Invalid timestamp received: ${e.ts}`);
    return null;
}

const year = dt.getFullYear();
const month = String(dt.getMonth() + 1).padStart(2, '0');
const day = String(dt.getDate()).padStart(2, '0');
const hours = String(dt.getHours()).padStart(2, '0');
const minutes = String(dt.getMinutes()).padStart(2, '0');
const seconds = String(dt.getSeconds()).padStart(2, '0');

const ts = `${year}-${month}-${day} ${hours}:${minutes}:${seconds}`;

const slaveId = Number(e.slaveId);
const dpValue = Number(e.dpValue);
const alarm = (e.alarm || 'NORMAL').replace(/'/g, "''");

msg.topic = `INSERT INTO dp_log (slave_id, dp_value, alarm_status, logged_at) 
             VALUES (${slaveId}, ${dpValue}, '${alarm}', '${ts}')`;

msg.payload = {};

return msg;

if (!msg.payload || msg.payload.action !== 'set-active-ids') return null;

const raw = (msg.payload.raw || '').trim();
const ids = new Set();

raw.split(',').forEach(part => {
    part = part.trim();
    const rangeMatch = part.match(/^(\d+)-(\d+)$/);
    if (rangeMatch) { 
        const from = parseInt(rangeMatch[1]), to = parseInt(rangeMatch[2]); 
        for (let i = from; i <= to && i <= 200; i++) ids.add(i); 
    }
    else { 
        const n = parseInt(part); 
        if (!isNaN(n) && n >= 1 && n <= 200) ids.add(n); 
    }
});

const sorted = Array.from(ids).sort((a,b)=>a-b);
flow.set('activeSlaveIds', sorted, 'file');
flow.set('rrIndex', 0, 'file');

const tableData = flow.get('tableData', 'file') || {};
const settings = flow.get('deviceSettings', 'file') || {};
const allIds = flow.get('slaveIds', 'file') || [];

for (let id of allIds) {
    if (!ids.has(id)) {
        const device = settings['slave_' + id] || { Location: '', RoomNo: '', LSP: 0, HSP: 0 };
        tableData['slave_' + id] = { 
            ID: id, 
            Location: device.Location, 
            RoomNo: device.RoomNo, 
            DPValue: '—', 
            LSP: device.LSP, 
            HSP: device.HSP, 
            Alarm: 'OFFLINE', 
            Status: 'OFFLINE', 
            lastSeen: 0 
        };
    }
}
flow.set('tableData', tableData, 'file');

msg.payload = allIds.map(id => tableData['slave_' + id] || { 
    ID: id, Location: '', RoomNo: '', DPValue: '—', LSP: 0, HSP: 0, Alarm: 'OFFLINE', Status: 'OFFLINE', lastSeen: 0 
});

return msg;

if (!msg.payload || msg.payload.action !== 'auth-check') return null;

// Only superadmin and admin roles can authenticate for editing
const ALLOWED = {
    'Jetpace': 'Jetpace',
    'Admin':   'Admin'
};

const now       = Date.now();
const lockUntil = flow.get('authLockUntil', 'file') || 0;
if (now < lockUntil) {
    const secsLeft = Math.ceil((lockUntil - now) / 1000);
    msg.payload = { action: 'auth-result', success: false, locked: true, secsLeft };
    return msg;
}

const enteredId   = (msg.payload.userId   || '').trim();
const enteredPass = (msg.payload.password || '').trim();

if (ALLOWED[enteredId] && ALLOWED[enteredId] === enteredPass) {
    flow.set('authFailCount', 0, 'file');
    flow.set('authLockUntil', 0, 'file');
    msg.payload = { action: 'auth-result', success: true };
} else {
    let fails = (flow.get('authFailCount', 'file') || 0) + 1;
    flow.set('authFailCount', fails, 'file');
    if (fails >= 3) {
        flow.set('authLockUntil', now + 60 * 1000, 'file');
        flow.set('authFailCount', 0, 'file');
        msg.payload = { action: 'auth-result', success: false, locked: true, secsLeft: 60 };
    } else {
        msg.payload = { action: 'auth-result', success: false, locked: false, attemptsLeft: 3 - fails };
    }
}
return msg;

if (!msg.payload || msg.payload.action !== 'report-query') return null;

const p = msg.payload;
const slaveIds = (p.slaveIds || []).map(Number).filter(n => n >= 1 && n <= 200);

if (slaveIds.length === 0) {
    msg.payload = { action: 'report-result', error: 'No slave IDs selected.' };
    return [null, msg];
}
if (!p.dateFrom || !p.dateTo) {
    msg.payload = { action: 'report-result', error: 'Both From and To dates are required.' };
    return [null, msg];
}

const dateStart = p.dateFrom + ' 00:00:00';
const dateEnd = p.dateTo + ' 23:59:59';

let formatStr, groupBy;

if (p.interval === 'hourly') {
    formatStr = 'yyyy-MM-dd HH:00:00';
    groupBy = 'slave_id, FORMAT(logged_at, \'yyyy-MM-dd HH:00:00\')';
} else if (p.interval === 'minutely') {
    formatStr = 'yyyy-MM-dd HH:mm:00';
    groupBy = 'slave_id, FORMAT(logged_at, \'yyyy-MM-dd HH:mm:00\')';
} else {
    formatStr = 'yyyy-MM-dd';
    groupBy = 'slave_id, FORMAT(logged_at, \'yyyy-MM-dd\')';
}

const firstAlertSelect = `
    MIN(CASE WHEN alarm_status = 'ALERT' THEN logged_at ELSE NULL END) AS first_alert_ts,
    (
        SELECT TOP 1 dp_value 
        FROM dp_log AS inner_log 
        WHERE inner_log.slave_id = dp_log.slave_id 
          AND FORMAT(inner_log.logged_at, '${formatStr}') = FORMAT(dp_log.logged_at, '${formatStr}')
          AND inner_log.alarm_status = 'ALERT'
        ORDER BY inner_log.logged_at ASC
    ) AS first_alert_dp_value
`;

msg.topic = `
SELECT 
    slave_id, 
    FORMAT(logged_at, '${formatStr}') AS period, 
    ROUND(AVG(CAST(dp_value AS FLOAT)), 2) AS dp_value,
    0 AS had_alert
FROM dp_log 
WHERE slave_id IN (${slaveIds.join(',')}) 
  AND logged_at BETWEEN '${dateStart}' AND '${dateEnd}'
  AND alarm_status = 'NORMAL'
GROUP BY ${groupBy} 
ORDER BY slave_id, period
`;

msg.payload = {};
msg._reportMeta = { slaveIds, interval: p.interval, dateFrom: p.dateFrom, dateTo: p.dateTo };

return [msg, null];

if (!msg.payload || !msg.payload.action) return null;

if (msg.payload.action === 'save-options') {
    flow.set('locationOptions', msg.payload.locations || [], 'file');
    flow.set('roomNoOptions', msg.payload.rooms || [], 'file');
    return null;
}

if (msg.payload.action === 'load-options') {
    const locations = flow.get('locationOptions', 'file') || [];
    const rooms = flow.get('roomNoOptions', 'file') || [];
    msg.payload = { action: 'load-options', locations, rooms };
    return msg;
}

return null;

if (msg.error || msg.payload === undefined || msg.payload === null) {
    node.warn(`Modbus error or empty response for slave ${msg.slaveId || '?'}`);
    return [null, msg];
}

if (Buffer.isBuffer(msg.payload)) {
    msg.payload = Array.from(msg.payload);
}

if (!Array.isArray(msg.payload)) {
    if (msg.payload && Array.isArray(msg.payload.data)) {
        msg.payload = msg.payload.data;
    } else {
        msg.payload = [];
    }
}

return [msg, null];

if (!msg.payload) return null;

if (msg.payload.action === 'logout') {
    const socketId = msg._client ? msg._client.socketId : null;
    if (socketId) {
        let s = flow.get('authenticatedSockets') || {};
        delete s[socketId];
        flow.set('authenticatedSockets', s);
    }
    return null;
}

if (msg.payload.action !== 'login-check') return null;

const USERS = {
    'Jetpace': { password: 'Jetpace', role: 'superadmin', label: 'Super Admin' },
    'Admin': { password: 'Admin', role: 'admin', label: 'Admin' },
    'User': { password: 'User', role: 'user', label: 'User' }
};

const userId = (msg.payload.userId || '').trim();
const password = (msg.payload.password || '').trim();
const socketId = msg._client ? msg._client.socketId : 'unknown';
const now = Date.now();

const lockKey = 'loginLock_' + socketId;
const failKey = 'loginFails_' + socketId;
const lockUntil = flow.get(lockKey) || 0;

if (now < lockUntil) {
    const secsLeft = Math.ceil((lockUntil - now) / 1000);
    msg.payload = { action: 'login-result', success: false, locked: true, secsLeft };
    return [null, msg];
}

const fails = flow.get(failKey) || 0;
const user = USERS[userId];

if (user && user.password === password) {
    flow.set(failKey, 0);
    flow.set(lockKey, 0);

    let authSockets = flow.get('authenticatedSockets') || {};
    authSockets[socketId] = {
        ts: now,
        lastActivity: now,
        userId,
        role: user.role,
        label: user.label
    };
    flow.set('authenticatedSockets', authSockets);

    // Also store by userId so session-check can find it even if socketId shifts
    flow.set('lastLoginUser', userId, 'file');
    flow.set('lastLoginRole', user.role, 'file');
    flow.set('lastLoginLabel', user.label, 'file');
    flow.set('lastLoginTs', now, 'file');

    const client = msg._client;
    const navMsg = { payload: { page: 'DP', userId, role: user.role }, _client: client };
    const infoMsg = {
        payload: { action: 'login-result', success: true, userId, role: user.role, label: user.label },
        _client: client
    };
    return [navMsg, infoMsg];

} else {
    const newFails = fails + 1;
    flow.set(failKey, newFails);
    if (newFails >= 3) {
        flow.set(lockKey, now + 60000);
        flow.set(failKey, 0);
        msg.payload = { action: 'login-result', success: false, locked: true, secsLeft: 60 };
    } else {
        msg.payload = {
            action: 'login-result',
            success: false,
            locked: false,
            attemptsLeft: 3 - newFails
        };
    }
    return [null, msg];
}

// Receives from Update Row — ONLINE.
// msg._logEntry = { slaveId, dpValue, alarm, ts }
if (!msg._logEntry) return null;

const e = msg._logEntry;

msg.payload = {
    action: 'chart-live-point',
    slaveId: Number(e.slaveId),
    dpValue: Number(e.dpValue),
    alarm: e.alarm,
    ts: e.ts
};

return msg;

if (!msg.payload || !msg.payload.action) return null;

// chart-query → Build Chart Query
if (msg.payload.action === 'chart-query') return [msg, null];

// session-check / do-logout → Session Check + Logout node
if (msg.payload.action === 'session-check' || msg.payload.action === 'do-logout') return [null, msg];

return null;

if (!msg.payload || msg.payload.action !== 'chart-query') return null;

const p = msg.payload;
const slaveId = Number(p.slaveId);

if (isNaN(slaveId) || slaveId < 1 || slaveId > 200) {
    msg.payload = { action: 'chart-history-result', error: 'Invalid Slave ID (must be 1–200).' };
    return [null, msg];
}
if (!p.dateFrom || !p.dateTo) {
    msg.payload = { action: 'chart-history-result', error: 'Both From and To dates are required.' };
    return [null, msg];
}

const dateStart = p.dateFrom + ' 00:00:00';
const dateEnd   = p.dateTo   + ' 23:59:59';

let formatStr, groupBy;
if (p.interval === 'hourly') {
    formatStr = "yyyy-MM-dd HH:00:00";
    groupBy   = "FORMAT(logged_at, 'yyyy-MM-dd HH:00:00')";
} else if (p.interval === 'minutely') {
    formatStr = "yyyy-MM-dd HH:mm:00";
    groupBy   = "FORMAT(logged_at, 'yyyy-MM-dd HH:mm:00')";
} else {
    formatStr = "yyyy-MM-dd";
    groupBy   = "FORMAT(logged_at, 'yyyy-MM-dd')";
}

msg.topic = `
SELECT
    FORMAT(logged_at, '${formatStr}') AS period,
    ROUND(AVG(CAST(dp_value AS FLOAT)), 2) AS dp_value,
    MAX(CASE WHEN alarm_status = 'ALERT' THEN 1 ELSE 0 END) AS had_alert
FROM dp_log
WHERE slave_id = ${slaveId}
  AND logged_at BETWEEN '${dateStart}' AND '${dateEnd}'
GROUP BY ${groupBy}
ORDER BY period
`;

msg.payload = {};
msg._chartMeta = { slaveId, interval: p.interval, dateFrom: p.dateFrom, dateTo: p.dateTo };

return [msg, null];

const rows = msg.payload || [];
const meta  = msg._chartMeta || {};

msg.payload = {
    action: 'chart-history-result',
    rows: rows.map(r => ({
        period:    r.period,
        dp_value:  parseFloat(r.dp_value),
        had_alert: r.had_alert === 1 || r.had_alert === true
    })),
    meta:  meta,
    count: rows.length
};

return msg;

let slaveId = (msg.modbusRequest && msg.modbusRequest.unitid) || (msg.payload && msg.payload.unitid) || msg.slaveId || null;
if (!slaveId) { node.warn('ONLINE: slaveId not found'); return null; }

let raw = Array.isArray(msg.payload) ? msg.payload : (msg.payload && msg.payload.data ? Array.from(msg.payload.data) : []);

function toSigned16(val) { return val > 32767 ? val - 65536 : val; }

let settings = flow.get('deviceSettings', 'file') || {};
let device = settings['slave_' + slaveId] || { Location: '', RoomNo: '', LSP: -60, HSP: 60 };

let dpValue = toSigned16(raw[0] ?? 0);
let alarm = (dpValue < device.LSP || dpValue > device.HSP) ? 'ALERT' : 'NORMAL';
let now = Date.now();

let row = { 
    ID: slaveId, 
    Location: device.Location, 
    RoomNo: device.RoomNo, 
    DPValue: dpValue, 
    LSP: device.LSP, 
    HSP: device.HSP, 
    Alarm: alarm, 
    Status: 'ONLINE', 
    lastSeen: now 
};

let tableData = flow.get('tableData', 'file') || {};
tableData['slave_' + slaveId] = row;
flow.set('tableData', tableData, 'file');

let onlineIds = flow.get('onlineIds', 'file') || [];
if (!onlineIds.includes(slaveId)) { 
    onlineIds.push(slaveId); 
    onlineIds.sort((a,b)=>a-b); 
    flow.set('onlineIds', onlineIds, 'file'); 
}

const SLAVE_IDS = flow.get('slaveIds', 'file') || [];
msg.payload = SLAVE_IDS.map(id => tableData['slave_' + id] || { 
    ID: id, Location: '', RoomNo: '', DPValue: '—', LSP: -60, HSP: 60, Alarm: 'OFFLINE', Status: 'OFFLINE', lastSeen: 0 
});

msg._logEntry = { slaveId, dpValue, alarm, ts: now };
return msg;

if (!msg.payload) return null;

const SESSION_TIMEOUT = 5 * 60 * 1000;

if (msg.payload.action === 'do-logout') {
    const socketId = msg._client ? msg._client.socketId : null;
    if (socketId) {
        let s = flow.get('authenticatedSockets') || {};
        delete s[socketId];
        flow.set('authenticatedSockets', s);
    }
    // Clear persisted login info on explicit logout
    flow.set('lastLoginUser', null, 'file');
    flow.set('lastLoginRole', null, 'file');
    flow.set('lastLoginLabel', null, 'file');
    msg.payload = { action: 'navigate-login' };
    return msg;
}

if (msg.payload.action !== 'session-check') return null;

const socketId  = msg._client ? msg._client.socketId : null;
let authSockets = flow.get('authenticatedSockets') || {};
const session   = socketId ? authSockets[socketId] : null;
const now       = Date.now();

if (!session) {
    // Grace-period fallback: trust a recent persisted login (within 30s)
    // to handle the race between page load and socket session registration
    const lastUser  = flow.get('lastLoginUser',  'file');
    const lastRole  = flow.get('lastLoginRole',  'file');
    const lastLabel = flow.get('lastLoginLabel', 'file');
    const lastTs    = flow.get('lastLoginTs',    'file') || 0;

    if (lastUser && (now - lastTs) < 30000) {
        // Restore the session under the new socketId
        if (socketId) {
            authSockets[socketId] = {
                ts: now,
                lastActivity: now,
                userId: lastUser,
                role: lastRole,
                label: lastLabel
            };
            flow.set('authenticatedSockets', authSockets);
        }
        msg.payload = {
            action: 'session-result',
            authenticated: true,
            userId: lastUser,
            role:   lastRole,
            label:  lastLabel
        };
        return msg;
    }

    msg.payload = { action: 'navigate-login', reason: 'no-session' };
    return msg;
}

const lastActivity = session.lastActivity || session.ts || 0;

if ((now - lastActivity) > SESSION_TIMEOUT) {
    delete authSockets[socketId];
    flow.set('authenticatedSockets', authSockets);
    msg.payload = { action: 'navigate-login', reason: 'timeout' };
    return msg;
}

authSockets[socketId].lastActivity = now;
flow.set('authenticatedSockets', authSockets);

msg.payload = {
    action:        'session-result',
    authenticated: true,
    userId:        session.userId || 'admin',
    role:          session.role   || 'superadmin',
    label:         session.label  || 'Admin'
};
return msg;

format:
/* ===== REMOVE DEFAULT NODE-RED HEADER ===== */
md-toolbar,
.md-toolbar-tools,
.nrdb-ui-toolbar,
.nrdb-ui-header,
md-toolbar.md-default-theme,
md-toolbar.md-whiteframe-1dp {
  display: none !important;
  height: 0 !important;
  min-height: 0 !important;
  overflow: hidden !important;
}

/* ===== SIDEBAR ===== */
.nrdb-ui-sidebar {
  position: fixed !important;
  top: 54px;
  left: 0;
  width: 240px;
  height: calc(100vh - 54px) !important;
  background: linear-gradient(180deg, #0a0f1a 0%, #0b1120 100%) !important;
  overflow-y: auto;
  z-index: 1000;
  border-right: 1px solid rgba(255, 255, 255, 0.05);
}

/* Sidebar Items */
.nrdb-ui-sidebar md-list-item {
  color: #9ca3af !important;
  font-weight: 500;
  border-radius: 10px;
  margin: 6px 10px;
  transition: all 0.2s ease;
}

.nrdb-ui-sidebar md-list-item:hover {
  background: rgba(255, 255, 255, 0.06);
  color: #e5e7eb !important;
}

.nrdb-ui-sidebar .md-list-item._md-button.md-focused {
  background: linear-gradient(135deg, #0094CE, #0077b6) !important;
  color: #fff !important;
  box-shadow: 0 0 10px rgba(0, 148, 206, 0.4);
}

/* ===== MAIN CONTENT (FIXED SPACING) ===== */
.nrdb-ui-main {
  margin-left: 240px !important;
  margin-top: 54px !important;

  /* 🔥 Balanced spacing */
  padding-left: 10px !important;
  padding-right: 10px !important;

  background: #0f172a !important;
}

/* Remove unwanted outer spacing */
.nrdb-ui-page,
.nrdb-ui-content,
md-content {
  margin: 0 !important;
  padding: 0 !important;
}

/* Remove card extra margins */
.nrdb-ui-group,
.nrdb-ui-cardpanel,
md-card {
  margin-left: 0 !important;
  margin-right: 0 !important;
}

/* ===== TOP NAVBAR ===== */
#jetpace-topnav {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  height: 54px;

  background: linear-gradient(180deg, #0b1120 0%, #0a0f1a 100%);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 20px;

  z-index: 9999;

  border-bottom: 1px solid rgba(255, 255, 255, 0.06);
  box-shadow: 0 2px 12px rgba(0, 0, 0, 0.4);
}

/* Brand */
.jp-brand {
  display: flex;
  align-items: center;
  gap: 10px;
}

.jp-brand-logo {
  width: 32px;
  height: 32px;
  background: linear-gradient(135deg, #0094CE 0%, #005a8e 100%);
  border-radius: 8px;
}

.jp-brand-name {
  font-size: 16px;
  font-weight: 700;
  color: #e5e7eb;
}

/* Nav Pills */
.jp-nav-pills {
  background: rgba(255, 255, 255, 0.04);
  border-radius: 999px;
  padding: 4px;
  display: flex;
  gap: 4px;
  border: 1px solid rgba(255, 255, 255, 0.06);
}

.jp-nav-tab {
  padding: 6px 16px;
  border-radius: 999px;
  font-size: 13px;
  font-weight: 600;
  color: #9ca3af;
  transition: all 0.2s ease;
  cursor: pointer;
}

.jp-nav-tab:hover {
  color: #e5e7eb;
  background: rgba(255, 255, 255, 0.06);
}

.jp-nav-tab.jp-active {
  background: linear-gradient(135deg, #0094CE, #0077b6);
  color: #fff;
  box-shadow: 0 0 12px rgba(0, 148, 206, 0.4);
}

/* Right spacer */
.jp-spacer {
  width: 120px;
}

/* ===== SMOOTH UI TOUCHES ===== */
.nrdb-ui-sidebar {
  box-shadow: 4px 0 10px rgba(0, 0, 0, 0.3);
}

/* ===== TARGET THE EXACT TOP BLACK BAR ===== */
.nrdb-ui-group:first-child md-card,
.nrdb-ui-group:first-child .nrdb-ui-cardpanel,
.nrdb-ui-group:first-child .md-card {

