  padding-left: 0 !important;
}

func:
if (!msg.payload || !msg.payload.action) return null;

if (msg.payload.action === 'device-settings-save') {
    let d = msg.payload;
    let settings = flow.get('deviceSettings', 'file') || {};
    settings['slave_' + d.id] = {
        Location: d.location || '', RoomNo: d.roomNo || '',
        LSP: parseFloat(d.lsp) || 0, HSP: parseFloat(d.hsp) || 0
    };
    flow.set('deviceSettings', settings, 'file');
    let tableData = flow.get('tableData', 'file') || {};
    if (tableData['slave_' + d.id]) {
        tableData['slave_' + d.id].Location = d.location || '';
        tableData['slave_' + d.id].RoomNo   = d.roomNo   || '';
        tableData['slave_' + d.id].LSP      = parseFloat(d.lsp) || 0;
        tableData['slave_' + d.id].HSP      = parseFloat(d.hsp) || 0;
        flow.set('tableData', tableData, 'file');
    }
    return [null, null, null, null, null, null, null, null, null];
}

if (msg.payload.action === 'set-active-ids')                                   return [msg, null, null, null, null, null, null, null, null];
if (msg.payload.action === 'auth-check')                                       return [null, msg, null, null, null, null, null, null, null];
if (msg.payload.action === 'report-query')                                     return [null, null, msg, null, null, null, null, null, null];
if (msg.payload.action === 'save-options' || msg.payload.action === 'load-options') return [null, null, null, msg, null, null, null, null, null];
if (msg.payload.action === 'session-check' || msg.payload.action === 'do-logout')   return [null, null, null, null, msg, null, null, null, null];
if (msg.payload.action === 'alarm-report-query')                               return [null, null, null, null, null, msg, null, null, null];
if (msg.payload.action === 'ack-save')                                         return [null, null, null, null, null, null, msg, null, null];
// FIX: profile email and SMTP config now correctly routed to Handle Profile Update
if (msg.payload.action === 'profile-load-email' ||
    msg.payload.action === 'profile-save-email'  ||
    msg.payload.action === 'smtp-config-save'    ||
    msg.payload.action === 'send-email-alert')                                 return [null, null, null, null, null, null, null, msg, null];
if (msg.payload.action === 'settings-saved')                                   return [null, null, null, null, null, null, null, null, msg];

return [null, null, null, null, null, null, null, null, null];

const rows = msg.payload || [];
const meta = msg._reportMeta || {};
const settings = flow.get('deviceSettings', 'file') || {};

msg.payload = {
    action: 'report-result',
    rows: rows.map(r => {
        const d = settings['slave_' + r.slave_id] || { Location: '', RoomNo: '' };
        return { ...r, location: d.Location || '', roomNo: d.RoomNo || '' };
    }),
    meta,
    count: rows.length
};
return msg;

const rows = msg.payload || [];
const meta = msg._alarmMeta || {};
const settings = flow.get('deviceSettings', 'file') || {};
const acks = flow.get('alarmAcks', 'file') || {};

const enriched = rows.map(r => {
    const d = settings['slave_' + r.slave_id] || { Location: '', RoomNo: '', LSP: -60, HSP: 60 };
    const lsp = d.LSP != null ? d.LSP : -60;
    const hsp = d.HSP != null ? d.HSP : 60;
    const minDp = Number(r.min_alert_dp);
    const maxDp = Number(r.max_alert_dp);
    let alarmType = 'HIGH';
    if (minDp < lsp && maxDp <= hsp) alarmType = 'LOW';
    else if (maxDp > hsp && minDp < lsp) alarmType = 'HIGH';
    const alertDp = alarmType === 'LOW' ? minDp : maxDp;
    const ackKey = r.slave_id + '_' + r.period;
    return {
        slave_id:     Number(r.slave_id),
        period:       r.period,
        min_alert_dp: minDp,
        max_alert_dp: maxDp,
        alert_dp_value: alertDp,
        alarm_start:  r.alarm_start,
        alarm_end:    r.alarm_end,
        alert_count:  Number(r.alert_count),
        location:     d.Location || '',
        roomNo:       d.RoomNo   || '',
        lsp, hsp, alarmType,
        ack: acks[ackKey] || null
    };
});

msg.payload = { action: 'alarm-report-result', rows: enriched, meta, count: enriched.length };
return msg;

if (!msg.payload || msg.payload.action !== 'ack-save') return null;

const d = msg.payload;
const acks = flow.get('alarmAcks', 'file') || {};
const key = d.slaveId + '_' + d.period;

acks[key] = {
    slaveId:     d.slaveId,
    period:      d.period,
    destination: d.destination || '',
    alarmStart:  d.alarmStart,
    alarmEnd:    d.alarmEnd,
    ackedBy:     d.ackedBy || 'Unknown',
    ackedAt:     new Date().toISOString(),
    remarks:     d.remarks || ''
};
flow.set('alarmAcks', acks, 'file');

msg.payload = { action: 'ack-result', success: true, key, ack: acks[key] };
return msg;

if (!msg.payload) return null;
const p = msg.payload;

/* ─── Load profile email ─── */
if (p.action === 'profile-load-email') {
    const email      = flow.get('userEmail', 'file') || '';
    const smtpConfig = flow.get('smtpConfig', 'file') || {};
    msg.payload = { action: 'profile-email-data', email, smtpConfig };
    return msg;
}

/* ─── Save profile email (Jetpace or Admin only) ─── */
if (p.action === 'profile-save-email') {
    const ALLOWED = { 'Jetpace':'Jetpace', 'Admin':'Admin' };
    const enteredId   = (p.userId   || '').trim();
    const enteredPass = (p.password || '').trim();
    const newEmail    = (p.email    || '').trim();

    if (!ALLOWED[enteredId] || ALLOWED[enteredId] !== enteredPass) {
        msg.payload = { action: 'profile-email-result', success: false, error: 'Incorrect ID or password.' };
        return msg;
    }
    if (newEmail && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(newEmail)) {
        msg.payload = { action: 'profile-email-result', success: false, error: 'Invalid email format.' };
        return msg;
    }
    flow.set('userEmail', newEmail, 'file');
    msg.payload = { action: 'profile-email-result', success: true, email: newEmail };
    return msg;
}

/* ─── Save SMTP configuration (Jetpace or Admin only) ─── */
if (p.action === 'smtp-config-save') {
    const ALLOWED = { 'Jetpace':'Jetpace', 'Admin':'Admin' };
    if (!ALLOWED[p.userId] || ALLOWED[p.userId] !== p.password) {
        msg.payload = { action: 'smtp-config-result', success: false, error: 'Incorrect credentials.' };
        return msg;
    }
    const host = (p.host || '').trim();
    const port = parseInt(p.port) || 587;
    const user = (p.smtpUser || '').trim();
    const pass = (p.smtpPass || '').trim();
    const from = (p.from    || '').trim() || user;

    if (!host || !user || !pass) {
        msg.payload = { action: 'smtp-config-result', success: false, error: 'Host, username and password are required.' };
        return msg;
    }
    const config = { host, port, secure: port === 465, user, pass, from };
    flow.set('smtpConfig', config, 'file');
    // Return success — actual connectivity is verified on first email send
    msg.payload = { action: 'smtp-config-result', success: true, message: 'SMTP configuration saved successfully.' };
    return msg;
}

/* ─── Send email alert ─── */
if (p.action === 'send-email-alert') {
    const destEmail  = flow.get('userEmail', 'file') || '';
    const smtpConfig = flow.get('smtpConfig', 'file') || {};
    if (!destEmail || !smtpConfig.host) return null;   // no email configured

    // Fetch ack status if available
    const acks   = flow.get('alarmAcks', 'file') || {};
    const ackKey = String(p.slaveId) + '_' + (p.period || '');
    const ack    = acks[ackKey] || null;

    const ts = new Date(p.timestamp || Date.now()).toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' });
    const ackStatus = ack
        ? `Acknowledged\n  Acknowledged By : ${ack.ackedBy}\n  Acknowledged At : ${new Date(ack.ackedAt).toLocaleString('en-IN',{timeZone:'Asia/Kolkata'})}`
        : 'Pending — Not yet acknowledged';

    const body = [
        '╔══════════════════════════════════════════════╗',
        '║   JETPACE MONITORING SYSTEM — ALERT          ║',
        '╚══════════════════════════════════════════════╝',
        '',
        'DEVICE ALERT DETAILS',
        '────────────────────────────────────────────────',
        `  Slave ID       : ${p.slaveId}`,
        `  Location       : ${p.location  || '—'}`,
        `  Room Number    : ${p.roomNo    || '—'}`,
        `  Alert Value    : ${p.alertValue} (${p.alarm})`,
        `  Alert Time     : ${ts}`,
        '',
        'SESSION INFORMATION',
        '────────────────────────────────────────────────',
        `  Logged-in User : ${p.loggedInUser || 'Unknown'}`,
        '',
        'ACKNOWLEDGEMENT',
        '────────────────────────────────────────────────',
        `  Status         : ${ackStatus}`,
        '',
        '────────────────────────────────────────────────',
        'This is an automated alert from Jetpace Monitoring System.',
        'Please do not reply to this email.'
    ].join('\n');

    // Format message for node-red-node-email
    msg.to      = destEmail;
    msg.topic   = `[ALERT] Slave ${p.slaveId} — ${p.alarm} | Jetpace Monitor`;
    msg.payload = body;
    // Also carry SMTP options for dynamic send nodes
    msg._smtpConfig = smtpConfig;
    return [null, msg];   // output 2 → email node
}

return null;

if (!msg.payload || msg.payload.action !== 'alarm-report-query') return null;

const p = msg.payload;
const slaveIds = (p.slaveIds || []).map(Number).filter(n => n >= 1 && n <= 200);

if (slaveIds.length === 0) {
    msg.payload = { action: 'alarm-report-result', error: 'No slave IDs selected.' };
    return [null, msg];
}
if (!p.dateFrom || !p.dateTo) {
    msg.payload = { action: 'alarm-report-result', error: 'Both date fields are required.' };
    return [null, msg];
}

const dateStart = p.dateFrom + ' 00:00:00';
const dateEnd   = p.dateTo   + ' 23:59:59';

let formatStr, groupBy;
if (p.interval === 'hourly') {
    formatStr = 'yyyy-MM-dd HH:00:00';
    groupBy   = "slave_id, FORMAT(logged_at, 'yyyy-MM-dd HH:00:00')";
} else if (p.interval === 'minutely') {
    formatStr = 'yyyy-MM-dd HH:mm:00';
    groupBy   = "slave_id, FORMAT(logged_at, 'yyyy-MM-dd HH:mm:00')";
} else {
    formatStr = 'yyyy-MM-dd';
    groupBy   = "slave_id, FORMAT(logged_at, 'yyyy-MM-dd')";
}

msg.topic = `
SELECT
    slave_id,
    FORMAT(logged_at, '${formatStr}') AS period,
    MIN(CASE WHEN alarm_status='ALERT' THEN dp_value END) AS min_alert_dp,
    MAX(CASE WHEN alarm_status='ALERT' THEN dp_value END) AS max_alert_dp,
    MIN(CASE WHEN alarm_status='ALERT' THEN logged_at END) AS alarm_start,
    MAX(CASE WHEN alarm_status='ALERT' THEN logged_at END) AS alarm_end,
    COUNT(CASE WHEN alarm_status='ALERT' THEN 1 END) AS alert_count
FROM dp_log
WHERE slave_id IN (${slaveIds.join(',')})
  AND logged_at BETWEEN '${dateStart}' AND '${dateEnd}'
GROUP BY ${groupBy}
HAVING COUNT(CASE WHEN alarm_status='ALERT' THEN 1 END) > 0
ORDER BY slave_id, period
`;

msg.payload = {};
msg._alarmMeta = { slaveIds, interval: p.interval, dateFrom: p.dateFrom, dateTo: p.dateTo };
return [msg, null];
